import pytest_asyncio import httpx
@pytest_asyncio.fixture async def async_client() -> httpx.AsyncClient: """Async HTTP client for API testing.""" async with httpx.AsyncClient(timeout=30.0) as client: yield client
@pytest_asyncio.fixture async def app_client(app) -> httpx.AsyncClient: """Async client for FastAPI app via ASGI transport.""" async with httpx.AsyncClient( transport=httpx.ASGITransport(app=app), base_url="http://test", ) as client: yield client
@pytest_asyncio.fixture(scope="session") async def database(): """Async database setup — runs once for the session.""" from app.database import async_engine, Base
async with async_engine.begin() as conn: await conn.run_sync(Base.metadata.create_all)
yield async_engine
async with async_engine.begin() as conn: await conn.run_sync(Base.metadata.drop_all)
@pytest_asyncio.fixture async def db_session(database): """Async database session with rollback.""" from sqlalchemy.ext.asyncio import AsyncSession
async with AsyncSession(database) as session: async with session.begin(): yield session await session.rollback()

import pytest import asyncio
@pytest.mark.asyncio async def test_async_fetch_user(): user = await UserRepository.fetch_by_id(1) assert user.email == "user1@example.com"
@pytest.mark.asyncio async def test_concurrent_operations(): # Run multiple async operations concurrently results = await asyncio.gather( fetch_user(1), fetch_user(2), fetch_user(3), ) assert len(results) == 3 assert all(r is not None for r in results)
@pytest.mark.asyncio async def test_api_endpoint(app_client, database): response = await app_client.post( "/api/users", json={"email": "test@example.com"}, ) assert response.status_code == 201 assert response.json()["email"] == "test@example.com"

@pytest.mark.asyncio async def test_async_external_service(mocker): mock_fetch = mocker.patch( "app.services.external_api.fetch_data", new_callable=mocker.AsyncMock, ) mock_fetch.return_value = {"data": "mocked"}
result = await process_external_data()
assert result["data"] == "mocked" mock_fetch.assert_awaited_once()
@pytest.mark.asyncio async def test_async_exception_handling(mocker): mocker.patch( "app.services.external_api.fetch_data", new_callable=mocker.AsyncMock, side_effect=ConnectionError("Service unavailable"), )
with pytest.raises(ServiceError): await process_external_data()

@pytest.mark.asyncio @pytest.mark.timeout(5) async def test_slow_operation_completes(): result = await slow_async_operation() assert result is not None
@pytest.mark.asyncio async def test_operation_timeout_handling(): with pytest.raises(asyncio.TimeoutError): async with asyncio.timeout(1): await very_slow_operation()
@pytest.mark.asyncio async def test_wait_for_timeout(): with pytest.raises(asyncio.TimeoutError): await asyncio.wait_for(very_slow_operation(), timeout=0.1)

"""Async pytest configuration for FastAPI.""" import pytest import pytest_asyncio import httpx from sqlalchemy.ext.asyncio import create_async_engine, AsyncSession from sqlalchemy.orm import sessionmaker
from app.main import app from app.database import Base, get_db
TEST_DATABASE_URL = "sqlite+aiosqlite:///:memory:" test_engine = create_async_engine(TEST_DATABASE_URL, echo=False) TestSessionLocal = sessionmaker( bind=test_engine, class_=AsyncSession, expire_on_commit=False )
@pytest_asyncio.fixture(scope="session") async def setup_database(): async with test_engine.begin() as conn: await conn.run_sync(Base.metadata.create_all) yield async with test_engine.begin() as conn: await conn.run_sync(Base.metadata.drop_all)
@pytest_asyncio.fixture async def db_session(setup_database): async with TestSessionLocal() as session: yield session await session.rollback()
@pytest_asyncio.fixture async def client(db_session): """Test client with database dependency override.""" async def override_get_db(): yield db_session
app.dependency_overrides[get_db] = override_get_db
async with httpx.AsyncClient( transport=httpx.ASGITransport(app=app), base_url="http://test", ) as c: yield c
app.dependency_overrides.clear()
